############################################################ # PG Setup Code ############################################################ Context('Numeric'); $a = random(2,5,1); $answer1 = Compute("sqrt(x-$a)"); $answer1->{limits} = [$a+1,$a+4]; $answer2 = Compute("ln(abs( x / (x-$a) ))"); $answer2->{test_points} = [[-5],[-4],[1],[$a-1],[7],[8]]; $answer2evaluator = $answer2 -> cmp() -> withPostFilter( AnswerHints( [Compute("ln(abs((x-$a)/x))"),] => "This is the opposite of correct...",));
############################################################ # Body ############################################################
BEGIN_PGML a. Suppose the correct answer is [`\displaystyle [$answer1]\text{.}`]
+ [_]{$answer1}{15} [@AnswerFormatHelp('formulas')@]*
a. Suppose the correct answer is [`\displaystyle [$answer2]\text{.}`]
+ [_]{$answer2evaluator}{15} [@AnswerFormatHelp('formulas')@]*
END_PGML
